-- Case 028: set operations with nested windows, MINUS, INTERSECT, and ordered final output
WITH candidates AS(SELECT customer_id,tenant_id, 'high_value' AS reason FROM MART.CUSTOMER_360 WHERE lifetime_value >= 100000 UNION ALL SELECT customer_id,tenant_id, 'recent_growth' AS reason FROM MART.CUSTOMER_360 WHERE revenue_30d > revenue_30d_previous * 1.5 UNION ALL SELECT customer_id,tenant_id, 'support_risk' AS reason FROM MART.CUSTOMER_360 WHERE open_ticket_count >= 3),eligible AS(SELECT customer_id,tenant_id FROM candidates INTERSECT SELECT customer_id,tenant_id FROM CORE.CUSTOMER_CONSENT WHERE marketing_allowed),suppressed AS(SELECT customer_id,tenant_id FROM OPS.CAMPAIGN_SUPPRESSION WHERE CURRENT_DATE() BETWEEN suppressed_from AND suppressed_to),final_candidates AS(SELECT customer_id,tenant_id FROM eligible MINUS SELECT customer_id,tenant_id FROM suppressed),reason_rollup AS(SELECT c.customer_id,c.tenant_id,ARRAY_AGG(DISTINCT c.reason) WITHIN GROUP(ORDER BY c.reason) AS reasons,COUNT(DISTINCT c.reason) AS reason_count FROM candidates AS c INNER JOIN final_candidates AS f ON c.customer_id = f.customer_id AND c.tenant_id = f.tenant_id GROUP BY c.customer_id,c.tenant_id) SELECT r.tenant_id,r.customer_id,r.reasons,r.reason_count,ROW_NUMBER() OVER(PARTITION BY r.tenant_id ORDER BY r.reason_count DESC,r.customer_id) AS tenant_rank FROM reason_rollup AS r QUALIFY tenant_rank <= 1000 ORDER BY tenant_id,tenant_rank;
